```cpp
#pragma once

#include <ranges>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace batch_insert_products {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  float price;
  std::string category;
  int stock;
};

/**
 * Function: Perform efficient batch insertion of product data using a transaction.
 * 
 * @param products List of products to insert
 * @return true if all inserts succeed, false otherwise
 */
bool batch_insert_products(const std::vector<Product>& products) {
   using namespace sqlgen;
   using namespace sqlgen::literals;

   // Connect to SQLite database
   auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
   if (!conn_result) {
       return false;
   }

   // Drop table if exists and create new table
   auto result = conn_result
       .and_then(drop_table<Product> | if_exists)
       .and_then(create_table<Product> | if_not_exists);

   if (!result) {
       return false;
   }

   // Begin transaction
   auto transaction_result = result.and_then(begin_transaction);
   if (!transaction_result) {
       return false;
   }

   // Insert all products
   auto insert_result = transaction_result.and_then(insert(products));
   if (!insert_result) {
       // Rollback transaction on failure
       transaction_result.and_then(rollback);
       return false;
   }

   // Commit transaction
   auto commit_result = insert_result.and_then(commit);
   if (!commit_result) {
       // Rollback transaction on commit failure
       transaction_result.and_then(rollback);
       return false;
   }

   return true;
}

}  // namespace batch_insert_products
```

