Looking at the code fragments and the sqlgen library usage patterns, here's the complete implementation:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace delete_inactive_users {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::optional<sqlgen::DateTime> last_login;
  std::string status = "active";
};

int delete_inactive_users() {
  // Connect to the SQLite database
  auto db = sqlgen::sqlite::connect("test_db.sqlite");

  // Begin transaction
  db.begin_transaction();

  try {
    // Generate and execute the DELETE statement using sqlgen
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Create the DELETE statement with WHERE condition
    auto delete_stmt = delete_from<User>().where(less(&User::last_login, sqlgen::date("2025-01-01")));

    // Execute the statement
    delete_stmt.execute(db);

    // Commit the transaction and return the result
    return db.commit();
  }
  catch (const std::exception& e) {
    // Rollback transaction in case of error
    db.rollback();
    throw; // Re-throw the exception
  }
}

} // namespace delete_inactive_users
```

