```cpp
#pragma once

#include <optional>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace query_course_enrollment_stats {

struct Course {
  sqlgen::PrimaryKey<int> course_id;
  std::string title;
};

struct Enrollment {
  sqlgen::PrimaryKey<int> enrollment_id;
  sqlgen::ForeignKey<int, Course, "course_id"> course_id;
  std::optional<float> grade;
};

struct CourseStats {
  std::string title;
  int student_count;
  std::optional<double> avg_grade;
};

struct CourseStatsView {
  std::string title;
  int student_count;
  std::optional<double> avg_grade;
};

/**
 * Function: Calculate enrollment statistics per course.
 * 
 * @return List of course statistics
 */
std::vector<CourseStats> query_course_enrollment_stats() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to database and create tables
  auto result = sqlgen::sqlite::connect("test_db.sqlite")
      .and_then(create_table<Course> | if_not_exists)
      .and_then(create_table<Enrollment> | if_not_exists)
      .and_then([](auto&& conn) {
        // Build the query using sqlgen's query builder
        auto query = sqlgen::query<Course>()
            .left_join<Enrollment>(sqlgen::on<Course::course_id, Enrollment::course_id>)
            .group_by(&Course::course_id, &Course::title)
            .select(&Course::title, 
                   sqlgen::count(&Enrollment::enrollment_id).as("student_count"),
                   sqlgen::avg(&Enrollment::grade).as("avg_grade"));

        return conn.query(query);
      })
      .map([](auto&& rows) {
        // Convert the query result to CourseStats objects
        std::vector<CourseStats> stats;
        for (auto&& row : rows) {
          CourseStats cs;
          cs.title = std::get<0>(row);
          cs.student_count = std::get<1>(row);
          cs.avg_grade = std::get<2>(row);
          stats.push_back(std::move(cs));
        }
        return stats;
      });

  // Return the results or empty vector on error
  return result.value_or(std::vector<CourseStats>{});
}

}  // namespace query_course_enrollment_stats
```

