#pragma once

#include <ranges>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace query_customer_purchase_history {

struct Customer {
  sqlgen::PrimaryKey<int> customer_id;
  std::string name;
  std::string email;
};

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  double price;
};

struct Order {
  sqlgen::PrimaryKey<int> order_id;
  sqlgen::ForeignKey<int, Customer, "customer_id"> customer_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> order_date;
  double total_amount;
};

struct OrderItem {
  sqlgen::PrimaryKey<int> item_id;
  sqlgen::ForeignKey<int, Order, "order_id"> order_id;
  sqlgen::ForeignKey<int, Product, "product_id"> product_id;
  int quantity;
};

struct PurchaseHistory {
  std::string product_name;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> order_date;
  int quantity;
};


/**
 * Function: Retrieve a customer's purchase history with product details.
 * 
 * @param customer_id ID of the customer to query
 * @return List of purchase history items
 */
std::vector<PurchaseHistory> query_customer_purchase_history(int customer_id) {
  // Connect to SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Create tables if they don't exist
  conn.create_table<Customer>();
  conn.create_table<Product>();
  conn.create_table<Order>();
  conn.create_table<OrderItem>();

  // Build the query using sqlgen's fluent interface
  using namespace sqlgen;

  auto query = query<Customer>()
      .join<Order>(on<Customer, Order>(&Customer::customer_id, &Order::customer_id))
      .join<OrderItem>(on<Order, OrderItem>(&Order::order_id, &OrderItem::order_id))
      .join<Product>(on<OrderItem, Product>(&OrderItem::product_id, &Product::product_id))
      .where(column<Customer>(&Customer::customer_id) == customer_id)
      .order_by(column<Order>(&Order::order_date).desc())
      .select(
          column<Product>(&Product::name).as("product_name"),
          column<Order>(&Order::order_date),
          column<OrderItem>(&OrderItem::quantity)
      );

  // Execute the query and return results
  return conn.execute<PurchaseHistory>(query);
}

}  // namespace query_customer_purchase_history
