#pragma once

#include <ranges>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace query_daily_traffic_metrics {

struct PageVisit {
  sqlgen::PrimaryKey<int> visit_id;
  std::string url;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> visit_time;
};

struct DailyTraffic {
  std::string visit_date;
  int total_visits;
  int unique_pages;
};

struct DailyTrafficView {
  static constexpr const char* tablename = "DailyTrafficView";
  static constexpr bool is_view = true;
  std::string visit_date;
  int total_visits;
  int unique_pages;
};

/**
 * Function: Calculate daily traffic metrics from a log table.
 * 
 * @return List of daily traffic metrics
 */
std::vector<DailyTraffic> query_daily_traffic_metrics() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  auto conn_result = sqlite::connect("test_db.sqlite");
  if (!conn_result) return {};
  auto conn = conn_result.value();

  // Create table if not exists (helper)
  create_table<PageVisit>(conn);

  std::string view_sql = R"(
    CREATE VIEW IF NOT EXISTS DailyTrafficView AS
    SELECT strftime('%Y-%m-%d', visit_time) as visit_date, 
           COUNT(*) as total_visits, 
           COUNT(DISTINCT url) as unique_pages
    FROM PageVisit
    GROUP BY visit_date
    ORDER BY visit_date;
  )";

  exec(conn, view_sql);

  auto results = sqlgen::read<std::vector<DailyTrafficView>>(conn).value();

  // Convert to return type (or just return the view struct if we could change signature, but let's copy)
  std::vector<DailyTraffic> output;
  for (const auto& r : results) {
      output.push_back(DailyTraffic{.visit_date = r.visit_date, .total_visits = r.total_visits, .unique_pages = r.unique_pages});
  }

  return output;
}

}  // namespace query_daily_traffic_metrics

