namespace query_product_sales_report {

struct Product {
  static constexpr const char* tablename = "Product";
  sqlgen::PrimaryKey<int> product_id;
  std::string category;
};

struct Sale {
  static constexpr const char* tablename = "Sale";
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  double amount;
};

struct CategoryReport {
  std::string category;
  int total_qty;
  double total_amt;
};

struct ProductSalesReport {
  static constexpr const char* tablename = "ProductSalesReport";
  static constexpr bool is_view = true;
  std::string category;
  int total_qty;
  double total_amt;
};

std::vector<CategoryReport> query_product_sales_report() {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Build the query using sqlgen's fluent interface
    auto query = read<Product, Sale>()
                .join<Sale>(on("product_id"_c == "product_id"_c))
                .group_by("category"_c)
                .having(sum("amount"_c) > 5000)
                .select("category"_c, sum("quantity"_c).as("total_qty"), sum("amount"_c).as("total_amt"));

    // Execute the query against the SQLite database
