Looking at the code fragments and the requirements, I need to complete the `soft_delete_records` function using the `sqlgen` library. Based on the examples, here's the implementation:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace soft_delete_records {

struct Document {
  sqlgen::PrimaryKey<int> doc_id;
  std::string title;
  int is_deleted = 0;
  std::optional<sqlgen::DateTime> deleted_at;
};

bool soft_delete_records(const std::vector<int>& ids) {
    if (ids.empty()) {
        return true; // Nothing to delete
    }

    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Connect to the database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
        return false;
    }
    auto conn = std::move(*conn_result);

    // Create a transaction for batched updates
    auto transaction_result = conn.transaction();
    if (!transaction_result) {
        return false;
    }
    auto& transaction = *transaction_result;

    try {
        // Update each document individually in the transaction
        for (const auto& id : ids) {
            auto update_result = transaction.update<Document>(
                set("is_deleted"_c = 1, "deleted_at"_c = sqlgen::DateTime::now()),
                where("doc_id"_c == id)
            );

            if (!update_result) {
                transaction.rollback();
                return false;
            }
        }

        // Commit the transaction if all updates succeeded
        auto commit_result = transaction.commit();
        return static_cast<bool>(commit_result);
    } catch (...) {
        transaction.rollback();
        return false;
    }
}

}  // namespace soft_delete_records
```

