#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = std::move(conn_result).value();

  // Start transaction
  auto transaction = conn.transaction();

  try {
    // Check if sender has sufficient funds
    auto sender_result = sqlgen::read<Account>(where("account_id"_c == from_account_id));
    auto sender = conn.and_then(sender_result).value();

    if (sender.empty() || sender[0].balance < amount) {
      transaction.rollback();
      return false;
    }

    // Update sender's balance (deduct amount)
    auto update_sender = sqlgen::update<Account>(
        set(&Account::balance = &Account::balance - amount),
        where("account_id"_c == from_account_id)
    );

    auto sender_update_result = conn.and_then(update_sender);
    if (!sender_update_result) {
      transaction.rollback();
      return false;
    }

    // Update receiver's balance (add amount)
    auto update_receiver = sqlgen::update<Account>(
        set(&Account::balance = &Account::balance + amount),
        where("account_id"_c == to_account_id)
    );

    auto receiver_update_result = conn.and_then(update_receiver);
    if (!receiver_update_result) {
      transaction.rollback();
      return false;
    }

    // Commit transaction if all steps successful
    transaction.commit();
    return true;

  } catch (const std::exception& e) {
    // Rollback on any exception
    transaction.rollback();
    return false;
  }
}

