       .set(&Order::status, "expired")
       .where(sqlgen::equal(&Order::status, "pending") && 
              sqlgen::expr("order_date < DATE('now', '-7 days')"));

   int count1 = update1.execute();

   // Second update: shipped orders to delivered (simulating delivery confirmation)
   auto update2 = db.update<Order>()
       .set(&Order::status, "delivered")
       .where(sqlgen::equal(&Order::status, "shipped"));

   int count2 = update2.execute();

   // Return total number of rows affected
   return count1 + count2;
