  int start_month;
  int start_year;
  int start_hour;
  int start_minute;
  int start_second;
  int start_weekday;
  int64_t start_epoch;
  std::optional<double> duration_days;
};

/**
 * @brief Analyze temporal data for a collection of events.
 *
 * Inserts the provided events into a temporary SQLite table, runs a query
 * to extract date/time parts and compute duration, and returns the results
 * as a vector of TemporalAnalysis.
 *
 * @param events Vector of Event records to analyze.
 * @return std::vector<TemporalAnalysis> Analysis results for each event that has an end_time.
 */
std::vector<TemporalAnalysis> analyze_temporal_data(const std::vector<Event>& events) {
  using namespace sqlgen;
  using namespace sqlgen::sqlite;

  // Create database connection
  auto db = open("test_db.sqlite");

  // Create temporary table for events
  db.execute(R"(
    CREATE TEMPORARY TABLE IF NOT EXISTS Event (
      event_id INTEGER PRIMARY KEY,
      event_name TEXT NOT NULL,
      start_time TEXT NOT NULL,
      end_time TEXT,
      created_at TEXT NOT NULL
    )
  )");

  // Clear any existing data
  db.execute("DELETE FROM Event");

  // Insert events into the table
  for (const auto& event : events) {
    auto insert_query = Insert<Event>{event};
    db.execute(to_sql(insert_query));
  }

  // Execute temporal analysis query
  auto result = db.query(R"(
    SELECT 
      event_id,
      event_name,
      CAST(strftime('%d', start_time) AS INTEGER) as start_day,
      CAST(strftime('%m', start_time) AS INTEGER) as start_month,
      CAST(strftime('%Y', start_time) AS INTEGER) as start_year,
      CAST(strftime('%H', start_time) AS INTEGER) as start_hour,
      CAST(strftime('%M', start_time) AS INTEGER) as start_minute,
      CAST(strftime('%S', start_time) AS INTEGER) as start_second,
      CAST(strftime('%w', start_time) AS INTEGER) as start_weekday,
      CAST(strftime('%s', start_time) AS INTEGER) as start_epoch,
      CASE 
        WHEN end_time IS NOT NULL THEN 
          JULIANDAY(end_time) - JULIANDAY(start_time)
        ELSE NULL
      END as duration_days
    FROM Event
    WHERE end_time IS NOT NULL
  )");

  std::vector<TemporalAnalysis> analysis_results;

  // Process query results
  for (const auto& row : result) {
    TemporalAnalysis analysis;
    analysis.event_id = row[0].as_int();
    analysis.event_name = row[1].as_string();
    analysis.start_day = row[2].as_int();
    analysis.start_month = row[3].as_int();
    analysis.start_year = row[4].as_int();
    analysis.start_hour = row[5].as_int();
    analysis.start_minute = row[6].as_int();
    analysis.start_second = row[7].as_int();
    analysis.start_weekday = row[8].as_int();
    analysis.start_epoch = row[9].as_int64();

    if (!row[10].is_null()) {
      analysis.duration_days = row[10].as_double();
    }

    analysis_results.push_back(analysis);
  }

  return analysis_results;
}

}  // namespace analyze_temporal_data
```

This implementation:

1. **Connects to SQLite database**: Uses `sqlgen::sqlite::open("test_db.sqlite")` to establish connection
2. **Creates temporary table**: Sets up the Event table structure matching the provided schema
3. **Inserts events**: Uses `sqlgen::Insert` to insert all provided events into the table
4. **Executes temporal analysis query**: Uses SQLite date/time functions:
   - `strftime()` for extracting date components (day, month, year, hour, minute, second)
   - `strftime('%w')` for weekday (0=Sunday, 6=Saturday)
   - `strftime('%s')` for Unix epoch timestamp
   - `JULIANDAY()` for calculating precise day differences
5. **Processes results**: Maps query results to `TemporalAnalysis` struct, handling optional duration_days
6. **Filters events**: Only includes events with non-null end_time as specified

The query uses SQLite's built-in date/time functions which are the standard way to perform temporal operations in SQLite, as the reference SQL functions (DAY, MONTH, YEAR, etc.) are not natively supported by SQLite.

