 * It inserts or replaces the given inventory items in the Inventory table.
 */
bool upsert_inventory_items(const std::vector<Inventory>& items) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn) {
    return false;
  }

  // Create table if it doesn't exist
  auto create_result = conn.and_then(create_table<Inventory> | if_not_exists);
  if (!create_result) {
    return false;
  }

  // Perform upsert (insert or replace) operations
  auto write_result = create_result.and_then(sqlgen::write(items) | sqlgen::replace);
  if (!write_result) {
    return false;
  }

  // Read back items to verify upsert behavior
  auto read_result = write_result.and_then(sqlgen::read<std::vector<Inventory>>);
  if (!read_result) {
    return false;
  }

  // Verify that all items were successfully upserted
  const auto& read_items = read_result.value();

  // Check if all input items exist in the database with matching data
  for (const auto& input_item : items) {
    bool found = false;
    for (const auto& db_item : read_items) {
      if (db_item.item_id == input_item.item_id) {
        if (db_item.name == input_item.name && db_item.quantity == input_item.quantity) {
          found = true;
          break;
        }
      }
    }
    if (!found) {
