```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace calculate_order_metrics {

struct OrderItem {
  sqlgen::PrimaryKey<int> item_id;
  int order_id;
  int product_id;
  double unit_price;
  int quantity;
  std::optional<double> discount_rate;
  std::optional<double> tax_rate;
};

struct OrderMetrics {
  int item_id;
  int order_id;
  int product_id;
  double unit_price;
  int quantity;
  double discount_rate;
  double tax_rate;
  double gross_total;
  double discounted_total;
  double final_total;
  double unit_cost;
  int quantity_group;
  double estimated_profit;
};

/**
 * Calculate per-item order metrics by loading the provided items into a temporary SQLite table
 * and evaluating SQL expressions for totals, discounts, taxes, cost, grouping, and estimated profit.
 * @param items Vector of OrderItem records to analyze.
 * @return std::vector<OrderMetrics> Analysis results for each order item.
 */
std::vector<OrderMetrics> calculate_order_metrics_impl(const std::vector<OrderItem>& items) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to SQLite database
  auto conn = sqlite::connect("test_db.sqlite").value();

  // Create temporary table for OrderItem data
  auto create_result = create_table<OrderItem>(conn) | if_not_exists;
  if (!create_result) {
    throw std::runtime_error("Failed to create OrderItem table");
  }

  // Insert all items into the database
  auto write_result = write(conn, items);
  if (!write_result) {
    throw std::runtime_error("Failed to write OrderItem data");
  }

  // Define the SQL query with arithmetic operations for business metrics
  std::string query = R"(
    SELECT 
      item_id,
      order_id,
      product_id,
      unit_price,
      quantity,
      COALESCE(discount_rate, 0.0) as discount_rate,
      COALESCE(tax_rate, 0.0) as tax_rate,
      (unit_price * quantity) as gross_total,
      (unit_price * quantity * (1 - COALESCE(discount_rate, 0.0)/100)) as discounted_total,
      (unit_price * quantity * (1 - COALESCE(discount_rate, 0.0)/100) * (1 + COALESCE(tax_rate, 0.0)/100)) as final_total,
      (unit_price * quantity * 1.0 / quantity) as unit_cost,
      (quantity % 10) as quantity_group,
      (unit_price * 0.3) as estimated_profit
    FROM OrderItem
  )";

  // Execute query and retrieve results
  auto metrics_result = read<std::vector<OrderMetrics>>(conn, query);
  if (!metrics_result) {
    throw std::runtime_error("Failed to calculate order metrics");
  }

  return metrics_result.value();
}

}  // namespace calculate_order_metrics
```

