#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace join_orders_customers_payments {

struct Customer {
  sqlgen::PrimaryKey<int> customer_id;
  std::string name;
};

struct Order {
  sqlgen::PrimaryKey<int> order_id;
  int customer_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> order_date;
};

struct Payment {
  sqlgen::PrimaryKey<int> payment_id;
  int order_id;
  double amount;
};

struct Consolidated {
  sqlgen::PrimaryKey<int> order_id;
  std::string customer_name;
  double amount;
};

/**
 * description: join_orders_customers_payments.
 * This function demonstrates how to join three tables (Orders, Customers, and Payments)
 * and return a consolidated view with order_id, customer_name, and amount.
 * It orders the results by amount in descending order.
 * Returns: std::vector<Consolidated>.
 */
std::vector<Consolidated> join_orders_customers_payments() {
  // Create connection to SQLite database
  sqlgen::sqlite::Connection conn("test_db.sqlite");

  // Build the join query using sqlgen's query builder
  auto query = sqlgen::Select<
      sqlgen::Column<"o.order_id", int>,
      sqlgen::Column<"c.name", std::string>,
      sqlgen::Column<"p.amount", double>
  >{}
      .from<Order>("o")
      .inner_join<Customer>("c").on<"o.customer_id", "c.customer_id">()
      .inner_join<Payment>("p").on<"o.order_id", "p.order_id">()
      .order_by<"p.amount", sqlgen::Order::Desc>();

  // Execute the query and get results
  auto results = conn.query<Consolidated>(query);

  return results;
}

}  // namespace join_orders_customers_payments
