Here's the complete implementation of the `replace_text_in_notes` function:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <stdexcept>

namespace replace_text_in_notes {

struct Note {
  sqlgen::PrimaryKey<int> note_id;
  std::string content;
};

struct UpdatedNote {
  sqlgen::PrimaryKey<int> note_id;
  std::string updated_content;
};

/**
 * description: replace_text_in_notes.
 * This function demonstrates how to replace text in notes using sqlgen update API.
 * It replaces all occurrences of "foo" with "bar" in the content column of the Note table.
 * Returns: std::vector<UpdatedNote>.
 */
std::vector<UpdatedNote> replace_text_in_notes() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  try {
    // Connect to the SQLite database
    auto conn = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn) {
      throw std::runtime_error("Failed to connect to database");
    }

    // Create table if it doesn't exist
    conn.and_then(create_table<Note> | if_not_exists);

    // Update the content by replacing "foo" with "bar"
    // Use SQLite's REPLACE function for string replacement
    auto update_result = conn.and_then([](auto& conn) {
      return conn.execute(R"(
        UPDATE Notes 
        SET content = REPLACE(content, 'foo', 'bar')
      )");
    });

    if (!update_result) {
      throw std::runtime_error("Failed to update notes");
    }

    // Read the updated notes and convert to UpdatedNote format
    auto updated_notes = conn.and_then(read<std::vector<Note>>);

    if (!updated_notes) {
      throw std::runtime_error("Failed to read updated notes");
    }

    // Convert Note objects to UpdatedNote objects
    std::vector<UpdatedNote> result;
    for (const auto& note : updated_notes.value()) {
      result.push_back(UpdatedNote{
        .note_id = note.note_id,
        .updated_content = note.content
      });
    }

    return result;

  } catch (const std::exception& e) {
    throw std::runtime_error(std::string("Error in replace_text_in_notes: ") + e.what());
  }
}

}  // namespace replace_text_in_notes
```

