```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace analyze_department_employees {

struct Department {
  sqlgen::PrimaryKey<int> department_id;
  std::string department_name;
  std::string location;
};

struct Employee {
  sqlgen::PrimaryKey<int> employee_id;
  int department_id;
  std::string first_name;
  std::string last_name;
  double salary;
};

struct JoinResult {
  std::optional<std::string> department_name;
  std::optional<std::string> first_name;
  std::optional<std::string> last_name;
  std::optional<double> salary;
};

struct JoinAnalysis {
  std::vector<JoinResult> inner_join_results;
  std::vector<JoinResult> left_join_results;
  std::vector<JoinResult> right_join_results;
  std::vector<JoinResult> full_join_results;
};

/**
 * analyze_department_employees
 * Provides data-join analysis between Department and Employee input collections by
 * creating temporary SQL tables, inserting the provided rows, and executing a
 * variety of join queries to produce join-output samples.
 * Returns: JoinAnalysis.
 */
JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  JoinAnalysis analysis;

  // Connect to SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Create tables if they don't exist
  conn.and_then(create_table<Department> | if_not_exists);
  conn.and_then(create_table<Employee> | if_not_exists);

  // Clear existing data and insert new data
  conn.and_then(delete_from<Department>);
  conn.and_then(delete_from<Employee>);

  for (const auto& dept : depts) {
    conn.and_then(insert_into<Department>(dept));
  }

  for (const auto& emp : emps) {
    conn.and_then(insert_into<Employee>(emp));
  }

  // Perform INNER JOIN
  auto inner_join_query = 
    select(columns(
      "d.department_name"_c, 
      "e.first_name"_c, 
      "e.last_name"_c, 
      "e.salary"_c
    )) |
    from<Department>("d") |
    inner_join<Employee>("e") | on("d.department_id = e.department_id");

  auto inner_results = conn.and_then(inner_join_query | read<std::vector<JoinResult>>);
  if (inner_results) {
    analysis.inner_join_results = *inner_results;
  }

  // Perform LEFT JOIN (Employee LEFT JOIN Department)
  auto left_join_query = 
    select(columns(
      "d.department_name"_c, 
      "e.first_name"_c, 
      "e.last_name"_c, 
      "e.salary"_c
    )) |
    from<Employee>("e") |
    left_join<Department>("d") | on("e.department_id = d.department_id");

  auto left_results = conn.and_then(left_join_query | read<std::vector<JoinResult>>);
  if (left_results) {
    analysis.left_join_results = *left_results;
  }

  // Perform RIGHT JOIN (Employee RIGHT JOIN Department) - emulated with LEFT JOIN
  auto right_join_query = 
    select(columns(
      "d.department_name"_c, 
      "e.first_name"_c, 
      "e.last_name"_c, 
      "e.salary"_c
    )) |
    from<Department>("d") |
    left_join<Employee>("e") | on("d.department_id = e.department_id");

  auto right_results = conn.and_then(right_join_query | read<std::vector<JoinResult>>);
  if (right_results) {
    analysis.right_join_results = *right_results;
  }

  // Perform FULL JOIN - emulated with UNION of LEFT and RIGHT joins
  auto full_join_query = 
    select(columns(
      "d.department_name"_c, 
      "e.first_name"_c, 
      "e.last_name"_c, 
      "e.salary"_c
    )) |
    from<Employee>("e") |
    left_join<Department>("d") | on("e.department_id = d.department_id") |
    union_all(
      select(columns(
        "d2.department_name"_c, 
        "e2.first_name"_c, 
        "e2.last_name"_c, 
        "e2.salary"_c
      )) |
      from<Department>("d2") |
      left_join<Employee>("e2") | on("d2.department_id = e2.department_id") |
      where_("e2.employee_id IS NULL")
    );

  auto full_results = conn.and_then(full_join_query | read<std::vector<JoinResult>>);
  if (full_results) {
    analysis.full_join_results = *full_results;
  }

  return analysis;
}

}  // namespace analyze_department_employees
```

This implementation:

1. **Connects to the SQLite database** "test_db.sqlite" using the sqlgen library
2. **Creates the necessary tables** if they don't exist using the struct definitions
3. **Inserts the provided data** into the tables
4. **Performs all four join types**:
   - **INNER JOIN**: Gets only employees with assigned departments
   - **LEFT JOIN**: Includes all employees (even those without departments)
   - **RIGHT JOIN**: Emulated using LEFT JOIN to include all departments (even those without employees)
   - **FULL JOIN**: Emulated using UNION of LEFT JOIN and RIGHT JOIN to include all records
5. **Returns comprehensive analysis** with results from all join operations stored in the JoinAnalysis struct

The code uses the sqlgen library's fluent API for building SQL queries and handles optional fields in the JoinResult struct to accommodate NULL values from outer joins.

