namespace coalesce_function {

struct Profile {
  sqlgen::PrimaryKey<int> id;
  std::optional<std::string> nickname;
};

struct NicknameResult {
  std::string display_name;
};

/**
 * This function demonstrates COALESCE usage.
 * Returns: query value.
 */
inline auto coalesce_function() {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Construct a query that selects COALESCE(nickname, 'Anonymous') as display_name
    auto query = sqlgen::read<NicknameResult> |
                 sqlgen::from<Profile>() |
                 sqlgen::select(sqlgen::coalesce("nickname"_c, "Anonymous").as("display_name"));

    // Return the generated SQL query
    return sqlite::to_sql(query);
}

}  // namespace coalesce_function
