/**
 * Description: This function retrieves the top products based on total sales.
 * Returns: std::vector<TopProduct>.
 */
std::vector<TopProduct> get_top_products(size_t limit_count = 10) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  if (!conn) {
    // Return empty vector if connection fails
    return {};
  }

  // Build the query using sqlgen's DSL
  auto result = conn
    .and_then([limit_count](auto&& db) {
      // Create a custom query using sqlgen's select functionality
      // The query joins Product and Sales tables, calculates total sales,
      // groups by product, orders by total sales, and applies limit
      return sqlgen::read<std::vector<TopProduct>>(db, 
        select(
          "p.product_id"_c,
          "p.product_name"_c, 
          "p.category"_c,
          sqlgen::sum("p.price * s.quantity"_c).as("total_sales")
        )
        .from<Product>("p")
        .join<Sales>("s").on("p.product_id = s.product_id"_c)
        .group_by("p.product_id"_c, "p.product_name"_c, "p.category"_c)
        .order_by(sqlgen::desc("total_sales"_c))
        .limit(limit_count)
      );
    });

  if (result) {
    return result.value();
  } else {
    // Return empty vector if query fails
    return {};
  }
}

}  // namespace get_top_products
