/**
 * Description: This function tracks time metrics for each project, including day, month, year, hour, minute, second, and duration in days.
 * Returns: std::vector<TimeMetrics>.
 */
std::vector<TimeMetrics> project_time_tracking() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to SQLite database
  sqlite::Connection conn("test_db.sqlite");

  // Build the query using sqlgen
  auto query = select(
    Project::project_id,
    Project::name,
    function("strftime", "%d", TimeLog::start_time).as("day"),
    function("strftime", "%m", TimeLog::start_time).as("month"),
    function("strftime", "%Y", TimeLog::start_time).as("year"),
    function("strftime", "%H", TimeLog::start_time).as("hour"),
    function("strftime", "%M", TimeLog::start_time).as("minute"),
    function("strftime", "%S", TimeLog::start_time).as("second"),
    (function("julianday", TimeLog::end_time) - function("julianday", TimeLog::start_time)).as("duration_days")
  ).from<Project>().inner_join<TimeLog>(on(Project::project_id == TimeLog::project_id));

  // Execute the query and return results
  return conn.query<TimeMetrics>(query);
}

